INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (1, 'es', 'Curcumina. Colorante amarillo natural de la curcuma. Seguro. Tiene propiedades antiinflamatorias. Utilizado en productos de mostaza y curry.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (2, 'es', 'Riboflavina (Vitamina B2). Colorante amarillo-anaranjado natural. Seguro y nutritivo. Presente en muchos alimentos.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (3, 'es', 'Tartrazina. Colorante amarillo sintetico. Puede causar hiperactividad en ninos. Puede provocar reacciones alergicas. Sujeto a requisitos de etiquetado.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (4, 'es', 'Crisoina - colorante sintetico amarillo-anaranjado. PROHIBIDO en muchos paises incluida la UE. No deberia estar en el mercado.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (5, 'es', 'Amarillo de quinoleina. Colorante sintetico. Puede causar hiperactividad en ninos. Prohibido en algunos paises. Evitar si se es sensible.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (6, 'es', 'Amarillo rapido - colorante azoico. PROHIBIDO en la UE y EE.UU. Posible cancerigeno. No permitido.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (8, 'es', 'Amarillo 2G - colorante azoico. PROHIBIDO en la UE desde 2007 por riesgos genotoxicos. No utilizar.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (9, 'es', 'Amarillo ocaso. Colorante azoico. Puede causar hiperactividad en ninos y reacciones alergicas. Prohibido en algunos paises.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (10, 'es', 'Cochinilla (Carmina). Colorante rojo natural de insectos. Puede causar reacciones alergicas graves. No apto para vegetarianos.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (11, 'es', 'Orceina - colorante rojo. PROHIBIDO en la UE. Potencial cancerigeno.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (12, 'es', 'Carmoisina. Colorante rojo sintetico. Puede causar hiperactividad en ninos. Puede provocar asma. Prohibido en algunos paises.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (13, 'es', 'Amaranto - colorante rojo azoico. PROHIBIDO en EE.UU. desde 1976 (sospechoso de ser cancerigeno). En la UE permitido solo para caviar. EVITAR.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (14, 'es', 'Rojo Ponceau 4R. Colorante rojo sintetico. Puede causar hiperactividad en ninos. Relacionado con reacciones alergicas. Prohibido en EE.UU. y Noruega.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (15, 'es', 'Ponceau SX - colorante rojo. PROHIBIDO en muchos paises incluida la UE.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (16, 'es', 'Ponceau 6R - colorante rojo azoico. PROHIBIDO en la UE y EE.UU. Sospechoso de ser cancerigeno.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (17, 'es', 'Eritrosina - colorante rojo que contiene yodo. Posible disruptor tiroideo y sospechoso de ser cancerigeno. Prohibido en muchos paises. EVITAR.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (19, 'es', 'Rojo Allura. Colorante rojo sintetico. Puede causar hiperactividad en ninos. Posible alergeno. Ampliamente utilizado en EE.UU.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (20, 'es', 'Azul indantreno - colorante sintetico. PROHIBIDO en la UE. No utilizar.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (21, 'es', 'Azul patentado V. Colorante azul sintetico. Puede causar reacciones alergicas. Prohibido en varios paises incluidos EE.UU. y Australia.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (22, 'es', 'Indigotina (Indigo Carmina). Colorante azul sintetico. Puede causar nauseas y presion arterial alta. Posible alergeno.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (23, 'es', 'Azul brillante FCF. Colorante azul sintetico. Generalmente seguro pero puede causar reacciones alergicas en personas sensibles.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (24, 'es', 'Clorofilas - colorante verde natural extraido de plantas. Completamente seguro.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (25, 'es', 'Complejos cupricos de clorofilas - derivados de clorofila estabilizados con cobre. Seguros.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (26, 'es', 'Verde S/Verde acido brillante - colorante verde sintetico. Aprobado por EFSA pero prohibido en algunos paises (Canada, EE.UU., Japon). Posibles reacciones alergicas raras.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (27, 'es', 'Caramelo natural. Colorante marron natural. Generalmente seguro. Ampliamente utilizado en bebidas gaseosas y salsas.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (29, 'es', 'Caramelo de amoniaco. Colorante marron. Puede contener trazas de amoniaco. Generalmente reconocido como seguro en pequenas cantidades.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (30, 'es', 'Caramelo de sulfito amonico. El caramelo mas utilizado. Contiene sulfitos - puede causar reacciones en asmaticos. Comun en bebidas de cola.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (31, 'es', 'Negro brillante BN - colorante negro azoico. Posibles alergias. Prohibido en muchos paises (EE.UU., Canada, Japon). Deberia limitarse.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (32, 'es', 'Negro de carbon 7984 - colorante negro del carbon. PROHIBIDO en la UE por razones de seguridad.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (33, 'es', 'Carbon vegetal - colorante negro de la combustion de plantas. CONTROVERTIDO, puede interferir con medicamentos.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (34, 'es', 'Marron FK - colorante marron sintetico. Aprobado en la UE pero prohibido en muchos otros paises. Usar con precaucion.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (35, 'es', 'Marron HT/Marron chocolate - colorante marron sintetico. Aprobado por EFSA pero prohibido en algunos paises (EE.UU., Australia). Posibles alergias raras.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (36, 'es', 'Carotenos (Beta-caroteno). Colorante naranja natural y precursor de la vitamina A. Seguro y nutritivo. Presente en zanahorias y muchas verduras.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (38, 'es', 'Extracto de pimenton. Colorante rojo-anaranjado natural. Seguro. Derivado de pimientos de pimenton. Utilizado en quesos y salsas.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (47, 'es', 'Rojo de remolacha/Betanina - colorante rojo-purpura natural. Muy seguro.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (48, 'es', 'Antocianinas. Colorantes purpura-rojo naturales de frutas. Seguros. Presentes en bayas, uvas y col lombarda.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (49, 'es', 'Carbonato de calcio - colorante blanco, fuente de calcio. Completamente seguro.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (50, 'es', 'Dioxido de titanio - colorante blanco. EFSA evaluando su prohibicion por posibles riesgos (nanoparticulas). Francia ya lo prohibio desde 2020. EVITAR.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (51, 'es', 'Oxidos e hidroxidos de hierro - colorantes amarillos/rojos/negros. Naturales, muy seguros.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (52, 'es', 'Aluminio - colorante metalico. CONTROVERTIDO (vinculos con Alzheimer no demostrados pero se aconseja precaucion).');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (53, 'es', 'Plata - utilizada para decoraciones alimentarias. Costosa, inerte, no toxica.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (54, 'es', 'Oro - utilizado para decoraciones alimentarias. Completamente inerte.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (55, 'es', 'Litol Rubina BK/Pigmento Rubi - colorante rojo sintetico. Solo para corteza de queso. Uso limitado y especifico.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (57, 'es', 'Conservante comun. Generalmente seguro. Utilizado en bebidas, quesos y productos de panaderia.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (58, 'es', 'Sorbato de sodio - sal del acido sorbico. Seguro como E200.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (59, 'es', 'Sorbato de potasio. Conservante ampliamente utilizado. Generalmente reconocido como seguro. Presente en vino, queso y embutidos.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (60, 'es', 'Sorbato de calcio - como E200-202. Seguro.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (61, 'es', 'Acido benzoico. Conservante natural presente en bayas. Puede causar reacciones alergicas. No recomendado para ninos.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (62, 'es', 'Puede causar reacciones alergicas. Evitar con asma. Comun en bebidas gaseosas.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (63, 'es', 'Benzoato de potasio - como E211. Posibles alergias.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (64, 'es', 'Benzoato de calcio - como E211-212. Posibles alergias.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (65, 'es', 'Etil p-hidroxibenzoato (parabeno) - conservante. Posible disruptor endocrino. CONTROVERTIDO, limitar su uso.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (66, 'es', 'Etil p-hidroxibenzoato de sodio - como E214. Parabeno, CONTROVERTIDO.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (67, 'es', 'Propil p-hidroxibenzoato - conservante parabeno. Posible disruptor endocrino. PROHIBIDO en la UE desde 2006.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (68, 'es', 'Propil p-hidroxibenzoato de sodio - parabeno. PROHIBIDO en la UE junto con E216.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (69, 'es', 'Metil p-hidroxibenzoato - parabeno. Menos controvertido que E214-217 pero usar con precaucion.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (70, 'es', 'Metil p-hidroxibenzoato de sodio - como E218.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (71, 'es', 'Sulfitos - pueden causar reacciones en asmaticos. Utilizados en vino y frutas deshidratadas.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (72, 'es', 'Sulfito de sodio. Puede provocar ataques de asma. Destruye la vitamina B1. Comun en vino y frutas deshidratadas.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (73, 'es', 'Bisulfito de sodio - sulfito. Riesgo de alergias/asma.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (74, 'es', 'Metabisulfito de sodio - sulfito comun en el vino. Precaucion para asmaticos y alergicos.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (75, 'es', 'Metabisulfito de potasio - sulfito utilizado en vino. Precaucion para asmaticos.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (76, 'es', 'Sulfito de potasio - conservante sulfito. Como E220-224, precaucion para asmaticos. Destruye la vitamina B1.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (77, 'es', 'Sulfito de calcio - conservante. Precaucion para asmaticos, puede causar reacciones respiratorias graves.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (78, 'es', 'Bisulfito de calcio - conservante sulfito. Riesgo de alergias y asma como otros sulfitos.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (79, 'es', 'Bisulfito de potasio - conservante sulfito utilizado en vino. Precaucion para asmaticos.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (80, 'es', 'Bifenilo/Difenilo - conservante para citricos (en la piel). ALTAMENTE TOXICO si se ingiere. Siempre lavar la fruta tratada. Prohibido en algunos paises.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (81, 'es', 'Ortofenilfenol - fungicida para pieles de citricos. Posible cancerigeno. Lavar bien la fruta. Prohibido en algunos paises.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (82, 'es', 'Ortofenilfenato de sodio - como E231, fungicida para pieles. Siempre lavar la fruta tratada.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (83, 'es', 'Tiabendazol - fungicida sistemico para frutas. Puede penetrar la piel. Posibles efectos neurologicos. Limitar la exposicion.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (84, 'es', 'Nisina - bacteriostatico natural de fermentacion. Seguro, utilizado en quesos y conservas.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (85, 'es', 'Natamicina/Pimaricina - antifungico natural. Utilizado solo en la superficie de quesos y embutidos curados.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (89, 'es', 'Hexametilentetramina - conservante sintetico. Puede liberar formaldehido (cancerigeno). EVITAR. Prohibido en muchos paises.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (90, 'es', 'Formaldehido - conservante. CANCERIGENO DEMOSTRADO. PROHIBIDO en la UE para uso alimentario.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (91, 'es', 'Dimetil dicarbonato - conservante para bebidas. Se descompone rapidamente en CO2 y metanol (trazas).');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (92, 'es', 'Nitrito de potasio - conservante para carnes curadas. Como E250, puede formar nitrosaminas cancerigenas. ADI bajo, limitar embutidos.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (93, 'es', 'Nitrito de sodio. Utilizado en carnes curadas. Puede formar compuestos cancerigenos a altas temperaturas. Mantener un consumo moderado.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (94, 'es', 'Nitrato de sodio. Conservante en carnes curadas. Se convierte en nitrito en el cuerpo. Se aconseja un consumo moderado.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (95, 'es', 'Nitrato de potasio. Utilizado en carnes curadas y queso. Puede afectar la presion arterial. Limitar la ingesta.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (96, 'es', 'Acido acetico - vinagre. Completamente natural y seguro.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (97, 'es', 'Acetato de potasio - regulador de acidez. Sal del vinagre, completamente seguro.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (98, 'es', 'Acetato de sodio/Diacetato de sodio - regulador de acidez y conservante. Seguro, derivado del vinagre.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (99, 'es', 'Acetato de calcio - regulador de acidez. Seguro, tambien aporta calcio.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (100, 'es', 'Acetato de amonio - regulador de acidez. Seguro para uso alimentario.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (101, 'es', 'Acido lactico. Acido natural producido en los musculos y por fermentacion. Seguro. Comun en alimentos y bebidas fermentadas.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (102, 'es', 'Acido propionico - conservante antimoho. Seguro, tambien producido por el cuerpo.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (103, 'es', 'Propionato de sodio - como E280. Seguro.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (104, 'es', 'Propionato de calcio - conservante en pan. Seguro, tambien aporta calcio.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (106, 'es', 'Acido borico - conservante. CONTROVERTIDO: posible toxicidad reproductiva. Limitado o prohibido en muchos paises. EVITAR.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (107, 'es', 'Borax/Tetraborato de sodio - conservante. PROHIBIDO en la UE y muchos paises por toxicidad. No deberia estar presente.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (108, 'es', 'Dioxido de carbono - CO2. Completamente natural y seguro.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (109, 'es', 'Acido malico. Acido natural presente en las manzanas. Seguro. Utilizado en bebidas y golosinas por su acidez.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (110, 'es', 'Acido fumarico. Acido natural presente en muchas plantas. Seguro. Mas acido que el acido citrico. Utilizado en bebidas.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (111, 'es', 'Vitamina C. Antioxidante. Seguro y beneficioso. Presente en muchos alimentos.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (112, 'es', 'Ascorbato de sodio. Sal de la vitamina C. Antioxidante seguro. Utilizado en carnes curadas y bebidas.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (113, 'es', 'Ascorbato de calcio - vitamina C + calcio. Seguro y beneficioso.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (114, 'es', 'Ascorbato de potasio - sal de la vitamina C. Seguro, antioxidante.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (115, 'es', 'Esteres de acidos grasos del acido ascorbico. Antioxidante seguro.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (116, 'es', 'Extracto rico en tocoferoles (Vitamina E). Antioxidante natural. Seguro y nutritivo. Protege las grasas de la oxidacion.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (117, 'es', 'Alfa-tocoferol - Vitamina E. Esencial, potente antioxidante, seguro.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (118, 'es', 'Gamma-tocoferol - forma natural de la vitamina E. Antioxidante seguro.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (119, 'es', 'Delta-tocoferol - vitamina E natural. Antioxidante seguro.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (120, 'es', 'Galato de propilo. Antioxidante sintetico. Puede causar reacciones alergicas en personas sensibles. Utilizado en grasas y aceites.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (121, 'es', 'Galato de octilo - antioxidante sintetico. CONTROVERTIDO como E310. Posibles alergias. Limitar.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (122, 'es', 'Galato de dodecilo - antioxidante sintetico. CONTROVERTIDO, posibles alergias y trastornos. Prohibido en algunos paises.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (123, 'es', 'Acido eritorbico/Acido isoascorbico - isomero de la vitamina C. Seguro, menor actividad vitaminica pero buen antioxidante.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (124, 'es', 'Eritorbato de sodio - sal del acido eritorbico. Seguro, antioxidante comun en carnes curadas.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (125, 'es', 'TBHQ (terc-butilhidroquinona) - potente antioxidante sintetico. CONTROVERTIDO: posibles efectos sobre el ADN, hiperactividad. Prohibido en Japon, restricciones en la UE. Limitar.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (126, 'es', 'BHA (Butilhidroxianisol). Antioxidante controvertido. Algunos estudios sugieren posibles riesgos para la salud. Prohibido en algunos paises.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (127, 'es', 'BHT (Butilhidroxitolueno). Antioxidante sintetico. Seguridad debatida. Puede causar reacciones alergicas. Utilizado en grasas y cereales.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (128, 'es', 'Lecitina. Emulsionante natural de la soja o los huevos. Seguro y beneficioso. Contiene colina. Muy ampliamente utilizado.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (129, 'es', 'Lactato de sodio. Sal del acido lactico. Seguro. Utilizado en productos carnicos y queso. Actua como conservante y humectante.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (130, 'es', 'Lactato de potasio - sal del acido lactico. Seguro, utilizado en bebidas deportivas.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (131, 'es', 'Lactato de calcio - aporta calcio. Seguro, utilizado en suplementos y alimentos.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (132, 'es', 'Lactato de amonio - regulador de acidez. NO PERMITIDO EN LA UE.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (133, 'es', 'Lactato de magnesio - aporta magnesio. NO PERMITIDO EN LA UE.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (134, 'es', 'Acido citrico. Acidificante natural. Generalmente seguro. Comun en bebidas.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (135, 'es', 'Citratos de sodio. Sales del acido citrico. Seguros. Utilizados como regulador de acidez en bebidas y mermeladas.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (136, 'es', 'Citrato de potasio - sal del acido citrico. Seguro.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (137, 'es', 'Citrato de calcio - fuente de calcio. Seguro y beneficioso.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (138, 'es', 'Acido tartarico - acido natural de la uva. Seguro, utilizado en vino y dulces.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (139, 'es', 'Tartrato de sodio - sal del acido tartarico. Seguro, regulador de acidez.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (140, 'es', 'Tartrato de potasio/Cremor tartaro - sal del acido tartarico. Seguro, levadura natural.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (141, 'es', 'Tartrato de sodio y potasio/Sal de Rochelle - sal doble. Seguro, utilizado en reposteria.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (142, 'es', 'Acido fosforico. Acidificante en bebidas de cola. El consumo excesivo puede afectar la absorcion de calcio. Contribuye a la erosion del esmalte dental.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (152, 'es', 'Fosfato de magnesio - regulador de acidez, fuente de magnesio. Seguro.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (153, 'es', 'Malato de sodio - sal del acido malico. Seguro, regulador de acidez.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (154, 'es', 'Malato de potasio - sal del acido malico. Seguro.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (155, 'es', 'Malato de calcio - sal del acido malico. Seguro, fuente de calcio.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (156, 'es', 'Acido metatartarico - derivado del acido tartarico. Seguro, estabilizante de vinos.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (157, 'es', 'Tartrato de calcio - sal del acido tartarico. Seguro.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (158, 'es', 'Acido adipico - acidificante sintetico. Seguro, utilizado en bebidas y levaduras quimicas.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (159, 'es', 'Adipato de sodio - sal del acido adipico. Seguro, regulador de acidez.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (160, 'es', 'Adipato de potasio - sal del acido adipico. Seguro.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (161, 'es', 'Acido succinico - acido organico natural. Seguro, presente en el cuerpo (ciclo de Krebs). Utilizado como potenciador del sabor.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (162, 'es', 'Fumarato de sodio - sal del acido fumarico. Posibles reacciones en personas sensibles.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (163, 'es', 'Fumarato de potasio - sal del acido fumarico. Seguro.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (164, 'es', 'Fumarato de calcio - sal del acido fumarico. Seguro, fuente de calcio.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (165, 'es', '1,4-Heptonolactona - acidificante. Seguro.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (166, 'es', 'Acido nicotinico/Niacina - Vitamina B3. Esencial, muy seguro. Utilizado como fortificante.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (167, 'es', 'Citrato de triamonio - sal del acido citrico. Seguro, regulador de acidez.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (168, 'es', 'Citrato ferrico de amonio - sal de hierro. Fuente de hierro. Posibles reacciones en personas sensibles.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (169, 'es', 'EDTA de calcio y disodio - secuestrante (quelante de metales). Seguro, previene la oxidacion y la rancidez.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (170, 'es', 'Acido alginico. Espesante natural de algas marinas. Seguro. Utilizado en helados y gelatinas. Puede inhibir la absorcion de nutrientes en grandes cantidades.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (171, 'es', 'Alginato de sodio. Espesante natural de algas marinas. Seguro. Comun en helados y pudines instantaneos.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (172, 'es', 'Alginato de potasio - de algas marinas. Seguro, espesante y gelificante natural.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (173, 'es', 'Alginato de amonio - de algas. Seguro, agente gelificante.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (174, 'es', 'Alginato de calcio - de algas. Seguro, utilizado en gastronomia molecular (esferificacion).');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (175, 'es', 'Alginato de propilenglicol - alga modificada. Seguro, emulsionante.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (176, 'es', 'Agar-agar - agente gelificante natural de algas rojas. Muy seguro, rico en fibra. Tambien utilizado como laxante natural.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (177, 'es', 'Carragenano. Espesante natural de algas rojas. Seguridad debatida - algunos estudios sugieren problemas digestivos. Utilizado en productos lacteos.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (180, 'es', 'Goma garrofin. Espesante natural del algarrobo. Seguro. Utilizado en helados y productos de panaderia.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (181, 'es', 'Goma guar. Espesante natural de las semillas de guar. Seguro en cantidades normales. Puede causar problemas digestivos en grandes cantidades.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (182, 'es', 'Tragacanto/Goma tragacanto - resina natural de arbustos. Seguro, espesante tradicional.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (183, 'es', 'Goma arabiga (Goma de acacia). Espesante natural de arboles de acacia. Seguro. Utilizado en confiteria y bebidas.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (184, 'es', 'Goma xantana. Polisacarido microbiano. Seguro. Excelente espesante y estabilizante. Utilizado en productos sin gluten.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (185, 'es', 'Goma karaya - resina natural de arboles. Seguro, espesante. Posibles alergias raras.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (186, 'es', 'Goma tara - de semillas. Seguro, espesante natural similar a la goma garrofin.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (187, 'es', 'Goma gellan - de fermentacion bacteriana. Seguro, potente agente gelificante. Utilizado en alternativas vegetales.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (188, 'es', 'Sorbitol. Alcohol de azucar. Puede causar efecto laxante en grandes cantidades. Utilizado en productos sin azucar. Generalmente seguro.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (189, 'es', 'Manitol. Alcohol de azucar. Puede tener efecto laxante. Utilizado en chicles y productos para diabeticos. Generalmente seguro.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (190, 'es', 'Glicerol/glicerina - humectante natural. Completamente seguro, tambien producido por el cuerpo. Puede ser de origen vegetal o animal.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (191, 'es', 'Hemicelulosa de soja - fibra de la soja. Seguro, prebiotico.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (192, 'es', 'Polioxietileno (8) estearato - emulsionante sintetico. NO PERMITIDO EN LA UE.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (193, 'es', 'Polioxietileno (40) estearato - emulsionante. Seguro.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (194, 'es', 'Polisorbato 20/Monolaurato de sorbitano polioxietilenado - emulsionante sintetico. Generalmente seguro, posibles alergias raras.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (195, 'es', 'Polisorbato 80/Monooleato de sorbitano polioxietilenado - emulsionante comun. Generalmente seguro pero estudios recientes sugieren precaucion con la microbiota intestinal. Moderacion.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (196, 'es', 'Polisorbato 40 - emulsionante. Utilizado en helados. Posibles alergias.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (197, 'es', 'Polisorbato 60 - emulsionante. Posibles alergias.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (198, 'es', 'Polisorbato 65 - emulsionante. Posibles alergias.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (201, 'es', 'Gelatina - proteina de huesos/piel/cartilago animal (cerdo/vacuno). NO VEGANO. NO HALAL (si es de cerdo). Neutro para la salud.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (202, 'es', 'Fosfatidos de amonio - emulsionante de la lecitina. Seguro, utilizado en chocolate.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (203, 'es', 'Isobutirato acetato de sacarosa - emulsionante en bebidas. Seguro segun EFSA, prohibido en algunos paises.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (204, 'es', 'Esteres gliceridos de resina de madera - emulsionante del pino. Seguro, utilizado en bebidas de citricos.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (205, 'es', 'Difosfatos (sodio/potasio/calcio) - reguladores de acidez y emulsionantes. Seguros PERO el exceso de fosfatos es problematico para los rinones. Presentes en muchos alimentos procesados. LIMITAR.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (206, 'es', 'Trifosfatos - emulsionantes y estabilizantes en carnes curadas/quesos. Como E450, limitar el exceso de fosfatos.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (207, 'es', 'Polifosfatos - potentes emulsionantes. Como E450-451, el EXCESO es problematico. Comunes en alimentos procesados. MODERACION.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (208, 'es', 'Beta-ciclodextrina - derivado del almidon. Seguro, utilizado para encapsular aromas.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (212, 'es', 'Metilcelulosa - derivado de la celulosa. Seguro, espesante y laxante natural.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (213, 'es', 'Etilcelulosa - derivado de la celulosa. Seguro, agente filmogeno.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (214, 'es', 'Hidroxipropilcelulosa - derivado de la celulosa. Seguro, espesante.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (215, 'es', 'Hidroxipropilmetilcelulosa/HPMC - derivado de la celulosa. Seguro, capsula vegetal para suplementos.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (216, 'es', 'Etilmetilcelulosa - derivado de la celulosa. Seguro.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (217, 'es', 'Carboximetilcelulosa - derivado de la celulosa. Seguro, espesante comun.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (218, 'es', 'Carboximetilcelulosa de sodio reticulada - celulosa modificada. Seguro.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (219, 'es', 'Carboximetilcelulosa hidrolizada enzimaticamente - celulosa modificada. Seguro.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (222, 'es', 'Mono- y digliceridos de acidos grasos. Emulsionante comun. Generalmente seguro. Puede derivar de fuentes animales o vegetales.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (227, 'es', 'Esteres de acido mono- y diacetiltartarico. Emulsionante utilizado en pan. Generalmente seguro. Mejora la fuerza de la masa.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (243, 'es', 'Carbonatos de sodio. Regulador de acidez y gasificante. Seguro. Comun en productos de panaderia. Tambien conocido como bicarbonato de sodio.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (245, 'es', 'Carbonatos de amonio. Gasificante para productos de panaderia. Seguro - se evapora durante el horneado. Utilizado en galletas y crackers.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (279, 'es', 'Dioxido de silicio. Antiaglomerante. Generalmente seguro. Presente en alimentos en polvo. Evita la formacion de grumos.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (280, 'es', 'Silicato de calcio. Antiaglomerante. Seguro. Utilizado en alimentos en polvo y granulados.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (297, 'es', 'Acido glutamico. Aminoacido natural. Potenciador del sabor. Generalmente seguro pero puede causar reacciones de sensibilidad al MSG en algunas personas.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (298, 'es', 'Glutamato monosodico (MSG). Potenciador del sabor controvertido. Puede causar dolores de cabeza y enrojecimiento en personas sensibles. Ampliamente utilizado en la cocina asiatica.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (299, 'es', 'Glutamato monopotasico. Potenciador del sabor similar al MSG. Puede causar reacciones en personas sensibles. Utilizado en alimentos procesados.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (300, 'es', 'Glutamato de calcio - potenciador del sabor. Como E621-622.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (301, 'es', 'Glutamato monoamonico - potenciador del sabor. Como MSG.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (302, 'es', 'Glutamato de magnesio - potenciador del sabor. Como MSG.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (303, 'es', 'Acido guanilico - nucleotido natural. Seguro, potencia el sabor umami. A menudo combinado con MSG.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (304, 'es', 'Guanilato disodico. Potenciador del sabor a menudo combinado con MSG. Derivado de pescado o levadura. No apto para personas con gota.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (305, 'es', 'Guanilato dipotasico - sal del acido guanilico. Seguro, potenciador.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (306, 'es', 'Guanilato de calcio - potenciador del sabor. Seguro.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (307, 'es', 'Acido inosinico - nucleotido natural de carne/pescado. Seguro, sabor umami.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (308, 'es', 'Inosinato disodico. Potenciador del sabor a menudo combinado con MSG. Puede desencadenar gota. Derivado de carne o pescado.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (309, 'es', 'Inosinato dipotasico - potenciador del sabor. Seguro.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (310, 'es', 'Inosinato de calcio - potenciador. Seguro.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (311, 'es', '5''-ribonucleotidos de calcio - mezcla E626+E630. Seguro, potente potenciador.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (312, 'es', '5''-ribonucleotidos disodicos - mezcla guanilato+inosinato. Ampliamente utilizado, seguro. Potencia el MSG.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (316, 'es', 'Cera de abejas - recubrimiento natural para frutas y golosinas. Seguro, natural. NO VEGANO.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (317, 'es', 'Cera de candelilla - cera vegetal de planta mexicana. Seguro, vegano.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (318, 'es', 'Cera de carnauba - de palmera brasilena. Seguro, la cera natural mas dura. Agente de recubrimiento.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (319, 'es', 'Goma laca - resina de insectos (Lac). Seguro para recubrimientos. NO VEGANO.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (320, 'es', 'Parafina/Cera microcristalina - de petroleo refinado. Seguro para recubrimientos, no se absorbe.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (322, 'es', 'Esteres del acido montanico - cera sintetica. Seguro, agente de recubrimiento.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (323, 'es', 'Cera de polietileno oxidado - cera sintetica. Seguro, recubrimiento.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (324, 'es', 'L-cisteina - aminoacido natural. Seguro, mejorador de harina. A menudo de plumas/cabello (no vegano) o fermentacion (vegano).');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (333, 'es', 'Argon - gas noble inerte. Seguro, utilizado como protector en envasado.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (334, 'es', 'Helio - gas noble. Seguro, raramente utilizado en alimentos.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (335, 'es', 'Nitrogeno - gas inerte. Seguro, utilizado en envasado y nata montada.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (336, 'es', 'Oxido nitroso - gas de la risa. Seguro para uso alimentario (nata montada). No inhalar directamente.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (339, 'es', 'Propano - gas. Seguro como propulsor.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (340, 'es', 'Oxigeno - gas. Seguro, raramente utilizado.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (341, 'es', 'Hidrogeno - gas. Seguro.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (342, 'es', 'Acesulfamo K. Edulcorante artificial. 200 veces mas dulce que el azucar. Generalmente reconocido como seguro. Estable al calor.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (343, 'es', 'Aspartamo. Edulcorante artificial. CONTROVERTIDO. Contiene fenilalanina - peligroso para pacientes con fenilcetonuria. Evitar si se es sensible.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (344, 'es', 'Ciclamato. Edulcorante artificial. Prohibido en EE.UU. desde 1969. Permitido en la UE pero CONTROVERTIDO. 30-50 veces mas dulce que el azucar.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (345, 'es', 'Sacarina. Primer edulcorante artificial. 300-500 veces mas dulce que el azucar. Seguro en cantidades moderadas. Regusto metalico.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (346, 'es', 'Sucralosa. Edulcorante artificial derivado del azucar. 600 veces mas dulce que el azucar. Estable al calor. Generalmente reconocido como seguro.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (347, 'es', 'Taumatina - proteina dulce de fruta africana. 2000 veces mas dulce que el azucar. Muy seguro, natural.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (348, 'es', 'Neohesperidina DC - edulcorante de citricos. 1000 veces mas dulce. Seguro, natural.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (349, 'es', 'Sal de aspartamo-acesulfamo - mezcla E951+E950. Seguro (con las mismas precauciones del aspartamo).');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (350, 'es', 'Maltitol. Alcohol de azucar. Aproximadamente 75-90% tan dulce como el azucar. Puede causar efecto laxante. Utilizado en productos sin azucar.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (351, 'es', 'Lactitol - alcohol de azucar de la lactosa. Seguro, prebiotico. Posible efecto laxante.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (352, 'es', 'Xilitol. Alcohol de azucar del abedul. Previene la caries dental. Puede causar problemas digestivos en grandes cantidades. Seguro para diabeticos.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (353, 'es', 'Eritritol - alcohol de azucar con cero calorias. Muy seguro, mejor tolerado que otros alcoholes de azucar. Sin efecto laxante.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (354, 'es', 'Extracto de quilaya - saponina de corteza de arbol sudamericano. Seguro, agente espumante natural en bebidas.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (355, 'es', 'Invertasa - enzima de levadura. Seguro, hidroliza la sacarosa. Utilizado en la produccion de miel artificial.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (356, 'es', 'Lisozima - enzima antibacteriana de clara de huevo. Seguro PERO de huevos (NO VEGANO). Posibles alergias.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (357, 'es', 'Polidextrosa - fibra soluble sintetica. Seguro, prebiotico. Leve efecto laxante.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (358, 'es', 'Polivinilpirrolidona/PVP - polimero sintetico. Seguro, estabilizante en bebidas y productos farmaceuticos.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (359, 'es', 'Polivinilpolipirrolidona - polimero. Seguro, estabilizante en vino y cerveza.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (379, 'es', 'Citrato de trietilo - ester. Seguro, disolvente y estabilizante.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (381, 'es', 'Diacetato de glicerilo/Diacetina - del glicerol. Seguro, disolvente y humectante.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (382, 'es', 'Triacetato de glicerilo/Triacetina - del glicerol. Seguro, disolvente de aromas.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (384, 'es', 'Propilenglicol/Propan-1,2-diol - alcohol. Seguro, humectante y disolvente. Ampliamente utilizado.');
INSERT INTO additive_translations (additive_id, language_code, notes) VALUES (385, 'es', 'Pectina. Agente gelificante natural de frutas. Seguro y beneficioso. Contiene fibra soluble. Utilizado en mermeladas y jaleas.');
